        prevent: (t)=>t.preventDefault(),
        self: (t)=>t.target !== t.currentTarget,
        ctrl: (t)=>!t.ctrlKey,
        shift: (t)=>!t.shiftKey,
        alt: (t)=>!t.altKey,
        meta: (t)=>!t.metaKey,
        left: (t)=>"button" in t && t.button !== 0,
        middle: (t)=>"button" in t && t.button !== 1,
        right: (t)=>"button" in t && t.button !== 2,
